    "path": "src/components/layout/Sidebar.tsx",
    "content": "import { NavLink, useLocation } from 'react-router-dom';
import {
    LayoutDashboard,
    Megaphone,
    Palette,
    FileCheck,
    ClipboardList,
    Settings,
    Users,
    Building2,
    LogOut,
    ChevronLeft,
    ChevronRight,
    BarChart,
    Briefcase,
    CreditCard,
    Search
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAuth, useIsSuperAdmin, useIsCompanyAdmin } from '@/contexts/AuthContext';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import logo1 from '@/assets/login/logo-1.jpeg';

interface NavItem {
    icon: React.ElementType;
    label: string;
    href: string;
    roles?: Array<'super_admin' | 'company_admin' | 'operador'>;
}

const mainNavItems: NavItem[] = [
    { icon: LayoutDashboard, label: 'Dashboard', href: '/dashboard' },
    // { icon: Search, label: 'Google Ads', href: '/google-ads' },
    { icon: Megaphone, label: 'Campanhas', href: '/campanhas' },
    { icon: Palette, label: 'Criativos', href: '/criativos' },
    { icon: FileCheck, label: 'Auditorias', href: '/auditorias' },
    { icon: ClipboardList, label: 'Pol√≠ticas', href: '/politicas' },
    { icon: BarChart, label: 'Relat√≥rios', href: '/relatorios' },
    { icon: Briefcase, label: 'Marca', href: '/brand' },
];

const settingsNavItems: NavItem[] = [
    { icon: Settings, label: 'Integra√І√µes', href: '/integracoes', roles: ['super_admin', 'company_admin'] },
    { icon: Users, label: 'Usu√°rios', href: '/usuarios', roles: ['super_admin', 'company_admin'] },
    { icon: Building2, label: 'Empresa', href: '/empresa', roles: ['super_admin', 'company_admin'] },
    { icon: CreditCard, label: 'Cobran√Іa', href: '/billing', roles: ['super_admin', 'company_admin'] },
];

export function Sidebar() {
    const location = useLocation();
    const { user, signOut } = useAuth();
    const isSuperAdmin = useIsSuperAdmin();
    const isCompanyAdmin = useIsCompanyAdmin();
    const [collapsed, setCollapsed] = useState(false);

    const filterByRole = (items: NavItem[]) => {
        return items.filter(item => {
            if (!item.roles) return true;
            if (!user?.role) return false;
            return item.roles.includes(user.role);
        });
    };

    const isActive = (href: string) => location.pathname === href;

    return (
        <aside
            className={cn(
                'h-screen bg-[#0c0d0a]/80 backdrop-blur-xl border-r border-white/5 flex flex-col transition-all duration-500 ease-in-out relative',
                collapsed ? 'w-20' : 'w-64'
            )}
        >
            {/* Logo */}
            <div className="h-20 flex items-center px-5 border-b border-white/5 overflow-hidden">
                <motion.div
                    layout
                    className="flex items-center gap-3"
                >
                    <div className="w-10 h-10 bg-gradient-to-br from-ch-orange to-[#e07d04] rounded-xl flex items-center justify-center shadow-lg shadow-ch-orange/20 flex-shrink-0 overflow-hidden">
                        <img src={logo1} alt="ClickHero" className="w-full h-full object-cover" />
                    </div>
                    {!collapsed && (
                        <motion.div
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex flex-col"
                        >
                            <span className="font-bold text-lg leading-tight tracking-tight text-ch-white">
                                Click<span className="text-ch-orange">.</span>Hero
                            </span>
                            <span className="text-[10px] uppercase tracking-[0.2em] text-ch-text-dimmed font-medium">
                                Intelig√™ncia Publicit√°ria
                            </span>
                        </motion.div>
                    )}
                </motion.div>
            </div>

            {/* Collapse Toggle */}
            <button
                onClick={() => setCollapsed(!collapsed)}
                className="absolute -right-3 top-24 w-7 h-7 bg-ch-dark-gray border border-white/10 rounded-full flex items-center justify-center hover:bg-ch-orange hover:border-ch-orange text-ch-text-muted hover:text-ch-black transition-all duration-300 z-50 shadow-xl"
            >
                {collapsed ? (
                    <ChevronRight className="w-4 h-4" />
                ) : (
                    <ChevronLeft className="w-4 h-4" />
                )}
            </button>

            {/* Main Navigation */}
            <nav className="flex-1 py-6 px-3 overflow-y-auto scrollbar-thin">
                <div className="space-y-1.5">
                    {mainNavItems.map((item, idx) => (
                        <motion.div
                            key={item.href}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.05 }}
                        >
                            <NavLink
                                to={item.href}
                                className={cn(
                                    'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                    isActive(item.href)
                                        ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                        : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                )}
                            >
                                {isActive(item.href) && (
                                    <motion.div
                                        layoutId="active-pill"
                                        className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                    />
                                )}
                                <item.icon className={cn(
                                    "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                    isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                )} />
                                {!collapsed && (
                                    <span className="truncate">{item.label}</span>
                                )}
                            </NavLink>
                        </motion.div>
                    ))}
                </div>

                {/* Settings Section */}
                {(isCompanyAdmin || isSuperAdmin) && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.4 }}
                    >
                        <div className="mt-8 mb-3 px-4">
                            {!collapsed ? (
                                <span className="text-[10px] font-bold uppercase tracking-wide text-ch-text-dimmed/60">
                                    Configura√І√µes
                                </span>
                            ) : (
                                <span className="text-[10px] font-black uppercase tracking-wide text-ch-text-muted mb-4 px-2 block">
                                    Configura√І√µes
                                </span>
                            )}
                        </div>
                        <div className="space-y-1.5">
                            {filterByRole(settingsNavItems).map((item, idx) => (
                                <motion.div
                                    key={item.href}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.5 + idx * 0.05 }}
                                >
                                    <NavLink
                                        to={item.href}
                                        className={cn(
                                            'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                            isActive(item.href)
                                                ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                                : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                        )}
                                    >
                                        {isActive(item.href) && (
                                            <motion.div
                                                layoutId="active-pill-settings"
                                                className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                            />
                                        )}
                                        <item.icon className={cn(
                                            "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                            isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                        )} />
                                        {!collapsed && (
                                            <span className="truncate">{item.label}</span>
                                        )}
                                    </NavLink>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}
            </nav>

            {/* User Section */}
            <div className="border-t border-white/5 p-4 bg-ch-black/20">
                {!collapsed ? (
                    <div className="flex items-center gap-2">
                        <NavLink
                            to="/settings"
                            className="flex items-center gap-3 flex-1 min-w-0 group cursor-pointer"
                        >
                            <div className="w-10 h-10 bg-gradient-to-br from-ch-dark-gray to-ch-black border border-white/5 group-hover:border-ch-orange/50 rounded-xl flex items-center justify-center text-ch-orange font-bold text-sm shadow-xl transition-all duration-300">
                                {user?.first_name?.[0]?.toUpperCase() || user?.email?.[0]?.toUpperCase() || 'U'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-sm font-bold text-ch-white truncate leading-tight group-hover:text-ch-orange transition-colors">
                                    {user?.first_name || 'Usu√°rio'}
                                </p>
                                <p className="text-[10px] text-ch-text-dimmed truncate uppercase tracking-wider">
                                    {user?.company?.name || 'Sem empresa'}
                                </p>
                            </div>
                        </NavLink>
                        <button
                            onClick={signOut}
                            className="p-2.5 text-ch-text-dimmed hover:text-rose-500 hover:bg-white/5 rounded-xl transition-all duration-300"
                            title="Sair"
                        >
                            <LogOut className="w-4 h-4" />
                        </button>
                    </div>
                ) : (
                    <button
                        onClick={signOut}
                        className="w-full h-11 text-ch-text-dimmed hover:text-ch-orange hover:bg-white/5 rounded-xl transition-all duration-300 flex items-center justify-center shadow-inner"
                        title="Sair"
                    >
                        <LogOut className="w-5 h-5" />
                    </button>
                )}
            </div>
        </aside >
    );
}
"
