                                        <div className="relative">
                                            <Lock className="absolute left-3 top-2.5 h-4 w-4 text-ch-text-muted" />
                                            <Input type="password" placeholder="вАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐ" className="pl-9 bg-white/5 border-white/10 text-ch-white" {...field} />
                                        </div>
