    "path": "src/hooks/useAudits.ts",
    "content": "import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Audit {
    id: string;
    company_id: string;
    creative_id: string;
    policy_id: string | null;
    status: string | null;
    compliance_score: number | null;
    performance_score: number | null;
    issues: AuditIssue[] | null;
    recommendations: string[] | null;
    ai_analysis: AiAnalysis | null;
    created_at: string;
    // Joined data
    creatives?: {
        name: string;
        image_url: string | null;
        type: string | null;
    };
    policies?: {
        name: string;
    };
}

export interface AuditIssue {
    type: 'keyword' | 'text_length' | 'brand' | 'performance';
    severity: 'error' | 'warning' | 'info';
    message: string;
    details?: Record<string, unknown>;
}

export interface AiAnalysis {
    quality_score?: number;
    tone_analysis?: string;
    strengths?: string[];
    weaknesses?: string[];
    suggestions?: string[];
}

export function useAudits() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;

    const auditsQuery = useQuery({
        queryKey: ['audits', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('audits')
                .select(`
          *,
          creatives(name, image_url, type),
          policies(name)
        `)
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(100);

            if (error) throw error;
            return data as unknown as Audit[];
        },
        enabled: !!companyId,
    });

    const runAudit = useMutation({
        mutationFn: async ({ creativeId, policyId }: { creativeId: string; policyId?: string }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-creative`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        creative_id: creativeId,
                        policy_id: policyId,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Audit failed');
            }

            return response.json();
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success('Auditoria conclu√≠da');
        },
        onError: (error) => {
            toast.error(`Erro na auditoria: ${error.message}`);
        },
    });

    const runBatchAudit = useMutation({
        mutationFn: async ({ campaignId, policyId, limit }: { campaignId?: string; policyId?: string; limit?: number }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-batch`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        campaign_id: campaignId,
                        policy_id: policyId,
                        limit,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Batch audit failed');
            }

            return response.json();
        },
        onSuccess: (data) => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success(`Auditoria em lote conclu√≠da: ${data.audited} criativos`);
        },
        onError: (error) => {
            toast.error(`Erro na auditoria em lote: ${error.message}`);
        },
    });

    return {
        audits: auditsQuery.data || [],
        isLoading: auditsQuery.isLoading,
        error: auditsQuery.error,
        runAudit,
        runBatchAudit,
    };
}

export function useAuditsCount() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['audits-count', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { count: total, error: totalError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId);

            if (totalError) throw totalError;

            const { count: pending, error: pendingError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId)
                .eq('status', 'pending');

            if (pendingError) throw pendingError;

            return {
                total: total || 0,
                pending: pending || 0
            };
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}

export function useRecentAudits(limit: number = 5) {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['recent-audits', companyId, limit],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('audits')
                .select(`
                    *,
                    creative:creatives(name, image_url)
                `)
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(limit);

            if (error) throw error;
            return data || [];
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}

export function useIssuesWithHighPriority(limit: number = 5) {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['high-priority-issues', companyId, limit],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('audits')
                .select(`
                    *,
                    creative:creatives(name, image_url)
                `)
                .eq('company_id', companyId)
                .eq('status', 'rejected')
                .order('created_at', { ascending: false })
                .limit(limit);

            if (error) throw error;
            return data || [];
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}
"
