    "path": "src/hooks/useCompanyMetrics.ts",
    "content": "import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export type MetricsPeriod = '7d' | '14d' | '30d' | '90d';

interface CompanyMetrics {
    totalSpend: number;
    totalImpressions: number;
    totalClicks: number;
    totalConversions: number;
    avgCtr: number;
    avgCpc: number;
    avgCpm: number;
    avgRoas: number;
    globalCpa: number;
    globalRoas: number;
    avgFrequency: number;
    previousPeriod: {
        totalSpend: number;
        totalImpressions: number;
        totalClicks: number;
        totalConversions: number;
        avgCtr: number;
        avgCpc: number;
        globalCpa: number;
        globalRoas: number;
        avgFrequency: number;
    };
    dailyData: Array<{
        date: string;
        impressions: number;
        clicks: number;
        spend: number;
        conversions: number;
        ctr: number;
    }>;
}

const getPeriodDays = (period: MetricsPeriod): number => {
    switch (period) {
        case '7d': return 7;
        case '14d': return 14;
        case '30d': return 30;
        case '90d': return 90;
        default: return 7;
    }
};

export function useCompanyMetrics(period: MetricsPeriod = '7d') {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['company-metrics', companyId, period],
        queryFn: async (): Promise<CompanyMetrics> => {
            if (!companyId) throw new Error('No company ID');

            const days = getPeriodDays(period);
            const today = new Date();
            const periodStart = new Date(today.getTime() - days * 24 * 60 * 60 * 1000);
            const previousPeriodStart = new Date(periodStart.getTime() - days * 24 * 60 * 60 * 1000);

            const formatDate = (d: Date) => d.toISOString().split('T')[0];

            // Current period metrics
            const { data: currentData, error: currentError } = await supabase
                .from('campaign_metrics')
                .select('date, impressions, clicks, spend, conversions, ctr, cpc, cpm, roas, frequency, campaigns!inner(platform)')
                .eq('company_id', companyId)
                .eq('campaigns.platform', 'meta')
                .gte('date', formatDate(periodStart))
                .lte('date', formatDate(today))
                .order('date', { ascending: true });

            if (currentError) throw currentError;

            // Previous period metrics
            const { data: previousData, error: previousError } = await supabase
                .from('campaign_metrics')
                .select('impressions, clicks, spend, conversions, ctr, cpc, roas, frequency, campaigns!inner(platform)')
                .eq('company_id', companyId)
                .eq('campaigns.platform', 'meta')
                .gte('date', formatDate(previousPeriodStart))
                .lt('date', formatDate(periodStart));

            if (previousError) throw previousError;

            // Aggregate current period
            const totals = (currentData || []).reduce(
                (acc, row) => ({
                    totalSpend: acc.totalSpend + (Number(row.spend) || 0),
                    totalImpressions: acc.totalImpressions + (Number(row.impressions) || 0),
                    totalClicks: acc.totalClicks + (Number(row.clicks) || 0),
                    totalConversions: acc.totalConversions + (Number(row.conversions) || 0),
                    ctrSum: acc.ctrSum + (Number(row.ctr) || 0),
                    cpcSum: acc.cpcSum + (Number(row.cpc) || 0),
                    cpmSum: acc.cpmSum + (Number(row.cpm) || 0),
                    roasSum: acc.roasSum + (Number(row.roas) || 0),
                    frequencySum: acc.frequencySum + (Number(row.frequency) || 0),
                    count: acc.count + 1,
                }),
                { totalSpend: 0, totalImpressions: 0, totalClicks: 0, totalConversions: 0, ctrSum: 0, cpcSum: 0, cpmSum: 0, roasSum: 0, frequencySum: 0, count: 0 }
            );

            // Aggregate previous period
            const prevTotals = (previousData || []).reduce(
                (acc, row) => ({
                    totalSpend: acc.totalSpend + (Number(row.spend) || 0),
                    totalImpressions: acc.totalImpressions + (Number(row.impressions) || 0),
                    totalClicks: acc.totalClicks + (Number(row.clicks) || 0),
                    totalConversions: acc.totalConversions + (Number(row.conversions) || 0),
                    ctrSum: acc.ctrSum + (Number(row.ctr) || 0),
                    cpcSum: acc.cpcSum + (Number(row.cpc) || 0),
                    roasSum: acc.roasSum + (Number(row.roas) || 0),
                    frequencySum: acc.frequencySum + (Number(row.frequency) || 0),
                    count: acc.count + 1,
                }),
                { totalSpend: 0, totalImpressions: 0, totalClicks: 0, totalConversions: 0, ctrSum: 0, cpcSum: 0, roasSum: 0, frequencySum: 0, count: 0 }
            );

            return {
                totalSpend: totals.totalSpend,
                totalImpressions: totals.totalImpressions,
                totalClicks: totals.totalClicks,
                totalConversions: totals.totalConversions,
                avgCtr: totals.count > 0 ? totals.ctrSum / totals.count : 0,
                avgCpc: totals.count > 0 ? totals.cpcSum / totals.count : 0,
                avgCpm: totals.count > 0 ? totals.cpmSum / totals.count : 0,
                avgRoas: totals.count > 0 ? totals.roasSum / totals.count : 0,
                // Global CPA = Total Spend / Total Conversions
                globalCpa: totals.totalConversions > 0 ? totals.totalSpend / totals.totalConversions : 0,
                // Global ROAS = (Conversion Value / Spend) - Assuming we don't have conversion value yet, defaulting to avgRoas for now or 0 if we want strictly calculated
                // Ideally ROAS should be Value / Spend. If we rely on platform reported ROAS, average is okay-ish but weighted is better.
                // Let's keep avgRoas as is, and add globalRoas if we had conversion_value.
                // For now, let's just expose avgRoas as globalRoas derived from platform data
                globalRoas: totals.count > 0 ? totals.roasSum / totals.count : 0,
                avgFrequency: totals.count > 0 ? totals.frequencySum / totals.count : 0,
                previousPeriod: {
                    totalSpend: prevTotals.totalSpend,
                    totalImpressions: prevTotals.totalImpressions,
                    totalClicks: prevTotals.totalClicks,
                    totalConversions: prevTotals.totalConversions,
                    avgCtr: prevTotals.count > 0 ? prevTotals.ctrSum / prevTotals.count : 0,
                    avgCpc: prevTotals.count > 0 ? prevTotals.cpcSum / prevTotals.count : 0,
                    globalCpa: prevTotals.totalConversions > 0 ? prevTotals.totalSpend / prevTotals.totalConversions : 0,
                    globalRoas: prevTotals.count > 0 ? prevTotals.roasSum / prevTotals.count : 0,
                    avgFrequency: prevTotals.count > 0 ? prevTotals.frequencySum / prevTotals.count : 0,
                },
                dailyData: (currentData || []).map(row => ({
                    date: row.date,
                    impressions: Number(row.impressions) || 0,
                    clicks: Number(row.clicks) || 0,
                    spend: Number(row.spend) || 0,
                    conversions: Number(row.conversions) || 0,
                    ctr: Number(row.ctr) || 0,
                })),
            };
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000, // 5 minutes
    });
}
"
  },
