                    { label: 'Est√°ticos', value: creatives.filter(c => c.type === 'image').length, icon: FileImage, color: 'blue-400' },
                    { label: 'Impress√µes Totais', value: formatNumber(creatives.reduce((acc, c) => acc + (c.impressions || 0), 0)), icon: TrendingUp, color: 'emerald-400' }
