                                                </div>

                                                <div className="mt-auto pt-6 border-t border-white/5 grid grid-cols-2 gap-4">
                                                    <div className="flex flex-col">
                                                        <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest mb-1">Exposi√І√£o</span>
