    "path": "src/pages/Empresa.tsx",
    "content": "import { useState } from 'react';
import { useCompany, useUpdateCompany, useCompanyStats } from '@/hooks/useCompany';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Building2,
    Users,
    Megaphone,
    Link2,
    FileCheck,
    Loader2,
    Save,
} from 'lucide-react';

export default function Empresa() {
    const { data: company, isLoading } = useCompany();
    const { data: stats } = useCompanyStats();
    const updateCompany = useUpdateCompany();

    const [form, setForm] = useState<{
        name: string;
    } | null>(null);

    const hasChanges = form !== null;

    const handleEdit = () => {
        if (company) {
            setForm({
                name: company.name || '',
            });
        }
    };

    const handleSave = async () => {
        if (!form) return;
        await updateCompany.mutateAsync(form);
        setForm(null);
    };

    const handleCancel = () => {
        setForm(null);
    };

    if (isLoading) {
        return (
            <div className="p-6 flex items-center justify-center min-h-[400px]">
                <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-ch-white">Empresa</h1>
                    <p className="text-ch-text-muted">
                        Configure as informa√І√µes da sua empresa
                    </p>
                </div>
                {!hasChanges ? (
                    <Button onClick={handleEdit} variant="outline" className="border-ch-dark-gray">
                        Editar
                    </Button>
                ) : (
                    <div className="flex gap-2">
                        <Button onClick={handleCancel} variant="outline" className="border-ch-dark-gray">
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={updateCompany.isPending}
                            className="bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {updateCompany.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Save className="w-4 h-4 mr-2" />
                            )}
                            Salvar
                        </Button>
                    </div>
                )}
            </div>

            {/* Limits Card */}
            <div className="glass rounded-xl p-6">
                <div className="flex items-center gap-4 mb-6">
                    <div className="p-3 rounded-xl bg-ch-orange/10">
                        <Building2 className="w-6 h-6 text-ch-orange" />
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-muted">Plano Atual</p>
                        <p className="text-xl font-bold text-ch-orange">Plano B√°sico</p>
                    </div>
                </div>

                {/* Limits */}
                <div className="grid grid-cols-3 gap-6 pt-6 border-t border-white/5">
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Campanhas</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.totalCampaigns || 0} / {company?.max_campaigns || 10}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-ch-orange transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalCampaigns || 0) / (company?.max_campaigns || 10)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Integra√І√µes</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.activeIntegrations || 0} / {company?.max_integrations || 2}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-blue-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.activeIntegrations || 0) / (company?.max_integrations || 2)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Usu√°rios</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.totalUsers || 0} / {company?.max_users || 5}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-purple-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalUsers || 0) / (company?.max_users || 5)) * 100)}%` }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Company Info */}
            <div className="glass rounded-xl p-6 space-y-6">
                <h2 className="font-semibold text-ch-white">Informa√І√µes da Empresa</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label className="text-sm text-ch-text-muted">Nome da Empresa</label>
                        {hasChanges ? (
                            <Input
                                value={form?.name || ''}
                                onChange={(e) => setForm(f => f && { ...f, name: e.target.value })}
                                className="bg-ch-dark-gray border-ch-dark-gray"
                            />
                        ) : (
                            <p className="text-ch-white font-medium">{company?.name || '-'}</p>
                        )}
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm text-ch-text-muted">Slug</label>
                        <p className="text-ch-white">{company?.slug || '-'}</p>
                    </div>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-ch-orange/10 rounded-lg">
                            <Megaphone className="w-5 h-5 text-ch-orange" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalCampaigns || 0}</p>
                            <p className="text-sm text-ch-text-muted">Campanhas</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-500/10 rounded-lg">
                            <Link2 className="w-5 h-5 text-blue-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.activeIntegrations || 0}</p>
                            <p className="text-sm text-ch-text-muted">Integra√І√µes</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-500/10 rounded-lg">
                            <Users className="w-5 h-5 text-purple-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalUsers || 0}</p>
                            <p className="text-sm text-ch-text-muted">Usu√°rios</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-green-500/10 rounded-lg">
                            <FileCheck className="w-5 h-5 text-green-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalAudits || 0}</p>
                            <p className="text-sm text-ch-text-muted">Auditorias</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
"
