                    </div>
                    <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase">Performance & Compliance</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Gest√£o avan√Іada de search, prote√І√£o de marca e leil√£o.</p>
                </div>
                {/* Bot√£o de Sincroniza√І√£o removido conforme solicita√І√£o para focar apenas na visualiza√І√£o */}
            </motion.div>

            <Tabs defaultValue="performance" className="space-y-6">
                <TabsList className="bg-white/5 border border-white/10 p-1 rounded-xl flex flex-wrap md:flex-nowrap gap-2 md:gap-0">
                    <TabsTrigger
                        value="performance"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <BarChart3 className="w-3.5 h-3.5 mr-2" />
                        Performance
                    </TabsTrigger>

                    <TabsTrigger
                        value="geo"
                        className="data-[state=active]:bg-blue-500 data-[state=active]:text-white h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <MapPin className="w-3.5 h-3.5 mr-2" />
                        Unidades e Localidades
                    </TabsTrigger>

                    <TabsTrigger
                        value="ai-creatives"
                        className="data-[state=active]:bg-purple-500 data-[state=active]:text-white h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <Sparkles className="w-3.5 h-3.5 mr-2" />
                        An√°lise de IA
                    </TabsTrigger>

                    <TabsTrigger
                        value="audit"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <AlertTriangle className="w-3.5 h-3.5 mr-2" />
                        Auditoria
                    </TabsTrigger>
                    <TabsTrigger
                        value="insights"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <Lightbulb className="w-3.5 h-3.5 mr-2" />
                        Insights do Leil√£o
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="performance" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsPerformance />
                </TabsContent>

                <TabsContent value="geo" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsGeo />
                </TabsContent>

                <TabsContent value="ai-creatives" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsAICreatives />
                </TabsContent>

                <TabsContent value="audit" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsAudit />
                </TabsContent>

                <TabsContent value="insights" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsInsights />
                </TabsContent>
            </Tabs>
        </motion.div>
    );
}
"
