  {
    "path": "src/pages/Login.tsx",
    "content": "import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { Eye, EyeOff, Loader2, ShieldCheck, Lock, Mail, ArrowRight, Activity, BarChart2, Globe } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

// Import assets
import logo1 from '@/assets/login/logo-1.jpeg';
import logo2 from '@/assets/login/logo-2.jpeg';
import logo3 from '@/assets/login/logo-3.jpeg';
import logo4 from '@/assets/login/logo-4.jpeg';

export default function Login() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const { signIn } = useAuth();
    const navigate = useNavigate();
    const { toast } = useToast();

    // Typing effect for title
    const [titleText, setTitleText] = useState('');
    const fullTitle = "ClickHero";

    useEffect(() => {
        let i = 0;
        const interval = setInterval(() => {
            setTitleText(fullTitle.slice(0, i + 1));
            i++;
            if (i >= fullTitle.length) clearInterval(interval);
        }, 150);
        return () => clearInterval(interval);
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!email || !password) {
            toast({
                title: 'Campos Obrigat√≥rios',
                description: 'Por favor, preencha suas credenciais de acesso.',
                variant: 'destructive',
            });
            return;
        }

        setLoading(true);
        const { error } = await signIn(email, password);
        setLoading(false);

        if (error) {
            toast({
                title: 'Erro de Autentica√І√£o',
                description: error.message === 'Invalid login credentials'
                    ? 'E-mail ou senha incorretos.'
                    : 'Ocorreu um erro ao tentar entrar. Tente novamente.',
                variant: 'destructive',
            });
        } else {
            toast({
                title: 'Acesso Permitido',
                description: 'Bem-vindo ao ClickHero.',
                className: "bg-ch-black border border-ch-orange/20 text-white",
            });
            navigate('/dashboard');
        }
    };

    return (
        <div className="min-h-screen w-full flex items-center justify-center bg-[#050505] relative overflow-hidden font-sans text-white selection:bg-ch-orange/30">
            {/* Background Effects */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[#050505]" />
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(207,111,3,0.05),transparent_60%)] animate-pulse" />
                {/* Grid Pattern */}
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:4rem_4rem] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_50%,#000_70%,transparent_100%)] opacity-20" />
            </div>

            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="relative z-10 w-full max-w-[1200px] grid grid-cols-1 lg:grid-cols-2 gap-0 lg:gap-12 p-4 lg:p-6"
            >
                {/* Left Side - Visuals - Only visible on large screens */}
                <div className="hidden lg:flex flex-col justify-center items-center space-y-12 p-10 relative">
                    {/* Decorative Elements */}
                    <div className="absolute top-10 left-10 w-20 h-20 border-l border-t border-ch-orange/20 rounded-tl-3xl" />
                    <div className="absolute bottom-10 right-10 w-20 h-20 border-r border-b border-ch-orange/20 rounded-br-3xl" />

                    <div className="relative group perspective-1000">
                        {/* Animated Rings - Orange theme */}
                        <div className="absolute -inset-12 bg-ch-orange/10 rounded-full blur-[60px] opacity-30 group-hover:opacity-50 transition-opacity duration-1000" />

                        <motion.div
                            animate={{ rotate: 360 }}
                            transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
                            className="absolute -inset-6 border border-dashed border-ch-orange/20 rounded-full"
                        />
                        <motion.div
                            animate={{ rotate: -360 }}
                            transition={{ duration: 25, repeat: Infinity, ease: "linear" }}
                            className="absolute -inset-3 border border-ch-orange/10 rounded-full"
                        />

                        {/* Main Logo Container */}
                        <div className="relative w-64 h-64 rounded-2xl bg-gradient-to-br from-ch-black-soft to-black border border-white/10 p-2 shadow-2xl transform transition-transform duration-500 hover:scale-105 hover:border-ch-orange/30 group-hover:shadow-[0_0_50px_rgba(207,111,3,0.15)] flex items-center justify-center overflow-hidden">
                            <div className="absolute inset-0 bg-gradient-to-tr from-ch-orange/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
                            <img
                                src={logo1}
                                alt="ClickHero Logo"
                                className="w-full h-full object-cover rounded-xl filter brightness-90 contrast-125 group-hover:brightness-100 transition-all duration-500"
                            />
                        </div>
                    </div>

                    <div className="text-center space-y-6">
                        <div className="space-y-2">
                            <h2 className="text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white via-white to-gray-400 tracking-tighter uppercase">
                                Intelig√™ncia <br /> <span className="text-ch-orange">Publicit√°ria</span>
                            </h2>
                            <p className="text-ch-text-muted text-sm font-medium tracking-[0.2em] uppercase max-w-md mx-auto leading-relaxed">
                                Domine seus dados. Escale seus resultados.
                            </p>
                        </div>

                        {/* Feature Pills */}
                        <div className="flex flex-wrapjustify-center gap-3 pt-4">
                            {[
                                { icon: Activity, label: "Monitoramento em Tempo Real" },
                                { icon: BarChart2, label: "An√°lise Preditiva" },
                                { icon: Globe, label: "Escala Global" }
                            ].map((feature, i) => (
                                <div key={i} className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/5 backdrop-blur-sm text-xs font-medium text-ch-text-muted hover:bg-white/10 hover:text-ch-white transition-colors cursor-default">
                                    <feature.icon className="w-3.5 h-3.5 text-ch-orange" />
                                    {feature.label}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Right Side - Login Form */}
                <div className="flex items-center justify-center">
                    <div className="w-full max-w-[450px] relative">
                        {/* Form Card Backdrop */}
                        <div className="absolute -inset-1 bg-gradient-to-b from-ch-orange/20 to-transparent rounded-[32px] blur-sm opacity-50" />

                        <div className="relative bg-[#0a0a0a] rounded-[30px] border border-white/10 shadow-2xl overflow-hidden p-8 md:p-10">
                            {/* Inner Glow */}
                            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1/2 h-1 bg-ch-orange shadow-[0_0_20px_rgba(207,111,3,0.8)]" />

                            {/* Header */}
                            <div className="space-y-8 mb-10">
                                <div className="space-y-4">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <div className="w-2 h-8 bg-ch-orange rounded-full shadow-[0_0_10px_rgba(207,111,3,0.5)]" />
                                            <span className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-[0.3em]">Portal de Acesso</span>
                                        </div>
                                        {/* Mobile Logo Fallback */}
                                        <div className="lg:hidden w-8 h-8 rounded-lg bg-ch-orange/10 border border-ch-orange/20 flex items-center justify-center">
                                            <span className="font-bold text-ch-orange">C</span>
                                        </div>
                                    </div>

                                    <h1 className="text-4xl font-bold tracking-tight text-white flex items-center gap-1">
                                        {titleText}<span className="text-ch-orange animate-pulse">_</span>
                                    </h1>
                                    <p className="text-ch-text-muted text-sm">
                                        Identifique-se para acessar o painel de controle.
                                    </p>
                                </div>
                            </div>

                            {/* Form */}
                            <form onSubmit={handleSubmit} className="space-y-6">
                                <div className="space-y-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="email" className="text-xs font-bold text-ch-text-muted uppercase tracking-wider ml-1">E-mail Corporativo</Label>
                                        <div className="relative group">
                                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-ch-text-dimmed group-focus-within:text-ch-orange transition-colors duration-300">
                                                <Mail className="w-5 h-5" />
                                            </div>
                                            <Input
                                                id="email"
                                                type="email"
                                                placeholder="usuario@empresa.com"
                                                value={email}
                                                onChange={(e) => setEmail(e.target.value)}
                                                className="bg-black/40 border-white/10 pl-12 h-14 focus:border-ch-orange/50 focus:ring-2 focus:ring-ch-orange/20 transition-all font-medium text-sm placeholder:text-ch-text-dimmed/30 rounded-xl"
                                                disabled={loading}
                                                autoComplete="email"
                                            />
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <div className="flex items-center justify-between ml-1">
                                            <Label htmlFor="password" className="text-xs font-bold text-ch-text-muted uppercase tracking-wider">Senha de Acesso</Label>
                                            <Link to="/forgot-password" className="text-[10px] uppercase font-bold text-ch-text-dimmed hover:text-ch-orange transition-colors">
                                                Esqueceu a senha?
                                            </Link>
                                        </div>
                                        <div className="relative group">
                                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-ch-text-dimmed group-focus-within:text-ch-orange transition-colors duration-300">
                                                <Lock className="w-5 h-5" />
                                            </div>
                                            <Input
                                                id="password"
                                                type={showPassword ? 'text' : 'password'}
                                                placeholder="вАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐвАҐ"
                                                value={password}
                                                onChange={(e) => setPassword(e.target.value)}
                                                className="bg-black/40 border-white/10 pl-12 pr-12 h-14 focus:border-ch-orange/50 focus:ring-2 focus:ring-ch-orange/20 transition-all font-medium text-sm placeholder:text-ch-text-dimmed/30 rounded-xl"
                                                disabled={loading}
                                                autoComplete="current-password"
                                            />
                                            <button
                                                type="button"
                                                onClick={() => setShowPassword(!showPassword)}
                                                className="absolute right-4 top-1/2 -translate-y-1/2 text-ch-text-dimmed hover:text-ch-white transition-colors p-1"
                                            >
                                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>
                                </div>

                                <div className="pt-4">
                                    <Button
                                        type="submit"
                                        className="w-full h-14 bg-gradient-to-r from-ch-orange to-ch-orange-hover hover:from-ch-orange-hover hover:to-ch-orange text-black font-black uppercase tracking-widest shadow-lg shadow-ch-orange/20 hover:shadow-ch-orange/40 transition-all duration-300 rounded-xl relative overflow-hidden group"
                                        disabled={loading}
                                    >
                                        <span className="relative z-10 flex items-center justify-center gap-3">
                                            {loading ? (
                                                <>
                                                    <Loader2 className="w-5 h-5 animate-spin" />
                                                    Validando...
                                                </>
                                            ) : (
                                                <>
                                                    Acessar Plataforma
                                                    <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                                                </>
                                            )}
                                        </span>
                                        <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out" />
                                    </Button>
                                </div>
                            </form>

                            {/* Footer */}
                            <div className="mt-8 pt-8 border-t border-white/5 flex flex-col items-center justify-between gap-4 text-xs">
                                <div className="flex flex-col md:flex-row items-center gap-4 w-full justify-between">
                                    <span className="text-ch-text-dimmed">
                                        N√£o tem uma conta?
                                    </span>
                                    <Link
                                        to="/register"
                                        className="font-bold text-ch-white hover:text-ch-orange transition-colors border border-white/10 hover:border-ch-orange/30 rounded-lg px-4 py-2 bg-white/5 hover:bg-white/10 flex items-center gap-2"
                                    >
                                        Solicitar Acesso
                                    </Link>
                                </div>

                                {/* Legal Links */}
                                <div className="flex items-center gap-6 text-[10px] uppercase font-bold text-ch-text-dimmed/50 mt-4">
                                    <Link to="/terms" className="hover:text-ch-white transition-colors">Termos de Uso</Link>
                                    <Link to="/privacy" className="hover:text-ch-white transition-colors">Pol√≠tica de Privacidade</Link>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </motion.div>
        </div>
    );
}
"
  },
  {
    "path": "src/pages/NotFound.tsx",
    "content": "import { useLocation } from "react-router-dom";
import { useEffect } from "react";

const NotFound = () => {
  const location = useLocation();

  useEffect(() => {
    console.error("404 Error: User attempted to access non-existent route:", location.pathname);
  }, [location.pathname]);

  return (
    <div className="flex min-h-screen items-center justify-center bg-muted">
