                                        "Acessar os dados.",
                                        "Corrigir dados incompletos ou inexatos.",
                                        "Solicitar a anonimiza√І√£o ou exclus√£o.",
                                        "Portabilidade dos dados."
                                    ].map((item, i) => (
                                        <div key={i} className="bg-white/5 p-3 rounded-lg text-sm text-ch-text-muted flex items-center gap-2 border border-white/5">
                                            <div className="w-1 h-1 bg-ch-orange rounded-full" />
                                            {item}
                                        </div>
                                    ))}
                                </div>
                            </section>

                            {/* 9. Reten√І√£o */}
                            <section id="retention" className="scroll-mt-32">
                                <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-3">
                                    <span className="bg-white/5 text-ch-orange text-sm font-mono py-1 px-2 rounded">09</span>
                                    Reten√І√£o de Dados
                                </h2>
                                <p className="text-ch-text-muted">
                                    Mantemos seus dados enquanto sua conta estiver ativa. Ap√≥s o cancelamento, dados n√£o essenciais s√£o exclu√≠dos em at√© 90 dias. Dados de faturamento podem ser mantidos por per√≠odos maiores para cumprimento de obriga√І√µes fiscais.
                                </p>
                            </section>

                            {/* 10. Contato */}
                            <section id="contact" className="scroll-mt-32 pb-12">
                                <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-3">
                                    <span className="bg-white/5 text-ch-orange text-sm font-mono py-1 px-2 rounded">10</span>
                                    Contato
                                </h2>
                                <div className="bg-gradient-to-r from-white/5 to-transparent p-6 rounded-xl border border-white/5">
                                    <p className="text-ch-text-muted mb-2">Para exercer seus direitos de privacidade ou contatar nosso DPO:</p>
                                    <a href="mailto:privacy@clickhero.com" className="text-xl font-bold text-ch-orange hover:text-white transition-colors">
                                        privacy@clickhero.com
                                    </a>
                                </div>
                            </section>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
"
