  {
    "path": "src/pages/Terms.tsx",
    "content": "import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { ArrowLeft, Scale, Check, ChevronRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const SECTIONS = [
    { id: 'intro', title: '1. Introdu√І√£o' },
    { id: 'definitions', title: '2. Defini√І√µes' },
    { id: 'account', title: '3. Conta e Acesso' },
    { id: 'usage', title: '4. Uso Aceit√°vel' },
    { id: 'ai-disclaimer', title: '5. Intelig√™ncia Artificial' },
    { id: 'payments', title: '6. Pagamentos e Planos' },
    { id: 'intellectual-property', title: '7. Propriedade Intelectual' },
    { id: 'liability', title: '8. Limita√І√£o de Responsabilidade' },
    { id: 'privacy', title: '9. Privacidade de Dados' },
    { id: 'termination', title: '10. Rescis√£o' },
    { id: 'changes', title: '11. Altera√І√µes' },
    { id: 'contact', title: '12. Contato' },
];

export default function Terms() {
    const navigate = useNavigate();
    const [activeSection, setActiveSection] = useState('intro');

    // Simple scroll spy
    useEffect(() => {
        const handleScroll = () => {
            const scrollPosition = window.scrollY + 150; // Offset

            for (const section of SECTIONS) {
                const element = document.getElementById(section.id);
                if (element && element.offsetTop <= scrollPosition) {
                    setActiveSection(section.id);
                }
            }
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const scrollToSection = (id: string) => {
        const element = document.getElementById(id);
        if (element) {
            const offset = 100;
            const elementPosition = element.getBoundingClientRect().top;
            const offsetPosition = elementPosition + window.pageYOffset - offset;
            window.scrollTo({
                top: offsetPosition,
                behavior: "smooth"
            });
            setActiveSection(id);
        }
    };

    return (
        <div className="min-h-screen bg-[#050505] text-white font-sans flex flex-col">
            {/* Header */}
            <div className="sticky top-0 z-50 bg-[#050505]/80 backdrop-blur-md border-b border-white/5">
                <div className="container mx-auto px-6 py-4 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(-1)}
                            className="text-ch-text-dimmed hover:text-white hover:bg-white/5"
                        >
                            <ArrowLeft className="w-4 h-4 mr-2" /> Voltar
                        </Button>
                        <div className="h-6 w-px bg-white/10 mx-2 hidden md:block" />
                        <div className="flex items-center gap-2">
                            <Scale className="w-5 h-5 text-ch-orange" />
                            <h1 className="text-lg font-bold uppercase tracking-tight hidden md:block">Termos de Uso</h1>
                        </div>
                    </div>
                    <div className="text-xs text-ch-text-dimmed uppercase tracking-wider font-medium">
                        √Ъltima atualiza√І√£o: {new Date().toLocaleDateString('pt-BR')}
                    </div>
                </div>
            </div>

            <div className="container mx-auto max-w-7xl px-6 py-12 flex-1 flex flex-col md:flex-row gap-12">
                {/* Sidebar Navigation */}
                <aside className="hidden md:block w-64 flex-shrink-0">
                    <div className="sticky top-32 space-y-1">
