        if (!campaign_id) throw new Error('Missing campaign_id');

        // Fetch Campaign Data
        const { data: campaign, error: campError } = await supabase
            .from('campaigns')
            .select(`
                *,
                ad_sets (*),
                creatives (*)
            `)
            .eq('id', campaign_id)
            .single();

        if (campError || !campaign) throw new Error('Campaign not found');

        // Fetch Metrics
        const { data: metrics } = await supabase
            .from('campaign_metrics')
            .select('*')
            .eq('campaign_id', campaign_id)
            .order('date', { ascending: false })
            .limit(30);

        // AI Analysis
        let aiAnalysis = null;
        let score = 70; // Default score

        if (openaiApiKey) {
            const prompt = `
                Voc√™ √© um consultor s√™nior de Marketing Digital (Meta Ads).
                Analise esta campanha e forne√Іa um diagn√≥stico estrat√©gico.

                DADOS DA CAMPANHA:
                Nome: ${campaign.name}
                Objetivo: ${campaign.objective}
                Status: ${campaign.status}
                Or√Іamento: ${campaign.daily_budget ? 'Di√°rio ' + campaign.daily_budget : 'Vital√≠cio ' + campaign.lifetime_budget}
                
                PERFORMANCE (√Ъltimos 30 dias):
                Total Gasto: ${metrics?.reduce((acc, m) => acc + m.spend, 0) || 0}
                Impress√µes: ${metrics?.reduce((acc, m) => acc + m.impressions, 0) || 0}
                Cliques: ${metrics?.reduce((acc, m) => acc + m.clicks, 0) || 0}
                Convers√µes: ${metrics?.reduce((acc, m) => acc + m.conversions, 0) || 0}

                ESTRUTURA:
                Qtd AdSets: ${campaign.ad_sets?.length || 0}
                Qtd Criativos: ${campaign.creatives?.length || 0}

                FORNE√ЗA EM JSON:
                1. quality_score (0-100)
                2. strengths (lista de pontos fortes)
                3. weaknesses (lista de pontos fracos/aten√І√£o)
                4. suggestions (lista de a√І√µes pr√°ticas para otimizar)
                5. tone_analysis (avalia√І√£o da estrutura)
            `;

