    "path": "supabase/functions/audit-creative/index.ts",
    "content": "import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AuditRequest {
    creative_id: string;
    policy_id?: string;
}

interface AuditIssue {
    type: 'keyword' | 'text_length' | 'brand' | 'performance';
    severity: 'error' | 'warning' | 'info';
    message: string;
    details?: Record<string, unknown>;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const openaiApiKey = Deno.env.get('OPENAI_API_KEY');
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { creative_id, policy_id } = await req.json() as AuditRequest;

        if (!creative_id) {
            throw new Error('Missing creative_id');
        }

        // Get creative
        const { data: creative, error: creativeError } = await supabase
            .from('creatives')
            .select('*')
            .eq('id', creative_id)
            .eq('company_id', userData.company_id)
            .single();

        if (creativeError || !creative) {
            throw new Error('Creative not found');
        }

        // Get policy (use default if not specified)
        let policy;
        if (policy_id) {
            const { data } = await supabase
                .from('policies')
                .select('*')
                .eq('id', policy_id)
                .single();
            policy = data;
        } else {
            const { data } = await supabase
                .from('policies')
                .select('*')
                .eq('company_id', userData.company_id)
                .eq('is_default', true)
                .single();
            policy = data;
        }

        const issues: AuditIssue[] = [];
        const recommendations: string[] = [];
        let complianceScore = 100;
        let performanceScore = 100;

        // === Rule-based checks ===

        const creativeText = [creative.text, creative.headline, creative.description]
            .filter(Boolean)
            .join(' ')
            .toLowerCase();

        if (policy) {
            // Check prohibited keywords
            if (policy.prohibited_keywords?.length) {
                for (const keyword of policy.prohibited_keywords) {
                    if (creativeText.includes(keyword.toLowerCase())) {
                        issues.push({
                            type: 'keyword',
                            severity: 'error',
                            message: `Palavra proibida encontrada: "${keyword}"`,
                            details: { keyword },
                        });
                        complianceScore -= 15;
                    }
                }
            }

            // Check required keywords
            if (policy.required_keywords?.length) {
                for (const keyword of policy.required_keywords) {
                    if (!creativeText.includes(keyword.toLowerCase())) {
                        issues.push({
                            type: 'keyword',
                            severity: 'warning',
                            message: `Palavra obrigat√≥ria ausente: "${keyword}"`,
                            details: { keyword },
                        });
                        complianceScore -= 5;
                    }
                }
            }

            // Check text length
            const textLength = creativeText.length;
            if (policy.min_text_length && textLength < policy.min_text_length) {
                issues.push({
                    type: 'text_length',
                    severity: 'warning',
                    message: `Texto muito curto (${textLength} caracteres, m√≠nimo: ${policy.min_text_length})`,
                    details: { current: textLength, min: policy.min_text_length },
                });
                complianceScore -= 10;
            }

            if (policy.max_text_length && textLength > policy.max_text_length) {
                issues.push({
                    type: 'text_length',
                    severity: 'warning',
                    message: `Texto muito longo (${textLength} caracteres, m√°ximo: ${policy.max_text_length})`,
                    details: { current: textLength, max: policy.max_text_length },
                });
                complianceScore -= 10;
            }

            // Check performance metrics
            const ctr = Number(creative.ctr) || 0;
            const cpc = Number(creative.cpc) || 0;

            if (policy.ctr_min && ctr > 0 && ctr < policy.ctr_min) {
                issues.push({
                    type: 'performance',
                    severity: 'warning',
                    message: `CTR abaixo do m√≠nimo (${ctr.toFixed(2)}% < ${policy.ctr_min}%)`,
                    details: { current: ctr, min: policy.ctr_min },
                });
                performanceScore -= 15;
                recommendations.push('Considere testar novas varia√І√µes de copy para melhorar o CTR');
            }

            if (policy.cpc_max && cpc > 0 && cpc > policy.cpc_max) {
                issues.push({
                    type: 'performance',
                    severity: 'warning',
                    message: `CPC acima do m√°ximo (R$${cpc.toFixed(2)} > R$${policy.cpc_max})`,
                    details: { current: cpc, max: policy.cpc_max },
                });
                performanceScore -= 15;
                recommendations.push('Revise a segmenta√І√£o e o lance para reduzir o CPC');
            }
        }

        // === AI Analysis (if OpenAI key available) ===
        let aiAnalysis = null;

        if (openaiApiKey && creativeText.length > 10) {
            try {
                const openaiResponse = await fetch('https://api.openai.com/v1/chat/completions', {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${openaiApiKey}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        model: 'gpt-4o-mini',
                        messages: [
                            {
                                role: 'system',
                                content: `Voc√™ √© um especialista em Pol√≠ticas de Publicidade do Meta (Facebook/Instagram) e Copywriting Persuasivo.
Analise o an√Їncio abaixo com RIGOR.

1. VERIFICA√З√ГO DE POL√НTICAS (Crucial):
- Identifique viola√І√µes de "Sa√Їde Pessoal" (antes/depois, zoom em partes do corpo).
- Promessas irrealistas ("Ganhe dinheiro r√°pido", "Perca 10kg em 1 dia").
- Linguagem ofensiva ou discriminat√≥ria.
- Categorias especiais n√£o declaradas (Cr√©dito, Emprego, Moradia, Temas Sociais).

2. AN√БLISE DE COPYWRITING:
- Avalie ganchos (Hooks).
- Clareza da oferta.
- Call to Action (CTA).

RETORNE JSON:
{
  "quality_score": (0-100),
  "policy_compliance_score": (0-100),
  "tone_analysis": "string",
  "strengths": ["string"],
  "weaknesses": ["string"],
  "policy_warnings": ["string"] (Lista de poss√≠veis viola√І√µes de pol√≠tica),
  "suggestions": ["string"] (A√І√µes para melhorar performance e aprova√І√£o)
}`,
                            },
                            {
                                role: 'user',
                                content: `Analise este criativo:\n\nTexto Principal: ${creative.text || '(Vazio)'}\nHeadline: ${creative.headline || '(Vazio)'}\nDescri√І√£o: ${creative.description || '(Vazio)'}\nCTA: ${creative.call_to_action || '(Vazio)'}\nTipo: ${creative.creative_format || 'Imagem'}`,
                            },
                        ],
                        temperature: 0.7,
                        max_tokens: 500,
                    }),
                });

                if (openaiResponse.ok) {
                    const openaiData = await openaiResponse.json();
                    const content = openaiData.choices?.[0]?.message?.content;
                    if (content) {
                        try {
                            aiAnalysis = JSON.parse(content);

                            // Add AI recommendations
                            if (aiAnalysis.suggestions?.length) {
                                recommendations.push(...aiAnalysis.suggestions.slice(0, 3));
                            }
                        } catch {
                            console.log('Failed to parse AI response');
                        }
                    }
                }
            } catch (error) {
                console.error('AI analysis error:', error);
            }
        }

        // Clamp scores
        complianceScore = Math.max(0, Math.min(100, complianceScore));
        performanceScore = Math.max(0, Math.min(100, performanceScore));

        // Determine status
        const hasErrors = issues.some(i => i.severity === 'error');
        const status = hasErrors ? 'rejected' : (complianceScore >= 80 ? 'approved' : 'pending');

        // Save audit result
        const { data: audit, error: auditError } = await supabase
            .from('audits')
            .insert({
                company_id: userData.company_id,
                creative_id,
                policy_id: policy?.id || null,
                status,
                compliance_score: complianceScore,
                performance_score: performanceScore,
                issues,
                recommendations,
                ai_analysis: aiAnalysis,
            })
            .select()
            .single();

        if (auditError) {
            console.error('Audit save error:', auditError);
            throw new Error('Failed to save audit');
        }

        return new Response(
            JSON.stringify({
                success: true,
                audit_id: audit.id,
                status,
                compliance_score: complianceScore,
                performance_score: performanceScore,
                issues_count: issues.length,
                has_ai_analysis: !!aiAnalysis,
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Audit error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});
